mapper.select:
SELECT id, request_id, event_type, topic, partition_key, status, retry_count, max_retry_count, last_error, to_char(created_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS created_at, to_char(updated_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS updated_at, to_char(next_retry_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS next_retry_at, to_char(locked_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS locked_at, to_char(published_at AT TIME ZONE 'Asia/Seoul', 'YYYY-MM-DD HH24:MI:SS') AS published_at FROM hub_job_outbox
status = #{status}
ORDER BY id DESC LIMIT #{limit}
